    spUi.install(uiDeps)
    spUi.installInputHooks(uiDeps)
    configureSpRefresh()
    ensureSpSpectateFrame()
    specCamera.install(specCameraDeps(deps.sampev))
    pcall(keysHud.installSampev, deps.sampev)
