    wmHandlerInstalled = true

    addEventHandler('onWindowMessage', function(msg, wparam, lparam)
        if msg == WM_ACTIVATEAPP then
            gameAppActive = (tonumber(wparam) or 0) ~= 0
            if gameAppActive then
                targetOfflineSinceAt = nil
            end
            return
