    deskCache.spMenuShowHandler = nil
    deskCache.spMenuHideHandler = nil
    deskCache.hookPrevSpMenuInit = nil
    deskCache.hookPrevSpMenuShow = nil
    deskCache.hookPrevSpMenuHide = nil
end

