-- Safe Call
local function SafeCall(label, fn, ...)
    if type(fn) ~= 'function' then
        print('[Report Desk] checker error [' .. tostring(label) .. ']: not a function')
        return false
    end
    local ok, err = pcall(fn, ...)
    if not ok then
        print('[Report Desk] checker error [' .. tostring(label) .. ']: ' .. tostring(err))
    end
    return ok, err
end

